import requests
from requests.auth import HTTPBasicAuth

BASE_URL = 'http://localhost:15672/api'
AUTH = HTTPBasicAuth('guest', 'guest')  # Use actual rabbitmq user credentials

def setup_vhost(vhost_name):
    url = f'{BASE_URL}/vhosts/{vhost_name}'
    response = requests.put(url, auth=AUTH)

    if response.status_code != 201:
        raise Exception(f'Failed to create vhost: {vhost_name}')

def setup_user(user, password):
    url = f'{BASE_URL}/users/{user}'
    data = {'password': password, 'tags': ''}
    response = requests.put(url, json=data, auth=AUTH)

    if response.status_code != 201:
        raise Exception(f'Failed to create user: {user}')

def set_permissions(vhost_name, user):
    url = f'{BASE_URL}/permissions/{vhost_name}/{user}'
    data = {'configure': '.*', 'write': '.*', 'read': '.*'}  
    response = requests.put(url, json=data, auth=AUTH)

    if response.status_code != 201:
        raise Exception(f'Failed to set permissions for: {user} on vhost: {vhost_name}')

def setup_rabbitmq(vhost_names, users_info):
    for vhost in vhost_names:
        setup_vhost(vhost)

    for user, password in users_info.items():
        setup_user(user, password)

    for vhost in vhost_names:
        for user in users_info.keys():
            set_permissions(vhost, user)

vhost_names = ['app1_vhost', 'app2_vhost']  # Add vhost names
users_info = {'user1': 'password1', 'user2': 'password2'}  # Add user info: {'username': 'password'}

setup_rabbitmq(vhost_names, users_info)